import{_ as d,o as a,c as r,ae as e}from"./chunks/framework.BeVX27ge.js";const c=JSON.parse('{"title":"對話練習","description":"","frontmatter":{},"headers":[],"relativePath":"practice.md","filePath":"practice.md"}'),l={name:"practice.md"};function o(i,t,h,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="對話練習" tabindex="-1">對話練習 <a class="header-anchor" href="#對話練習" aria-label="Permalink to &quot;對話練習&quot;">​</a></h1><blockquote><p>與 AI 客戶進行擬真銷售對話，磨練你的溝通技巧</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>對話練習是 AI Coach 的核心功能。您將與由 AI 驅動的虛擬客戶進行模擬銷售對話，客戶會根據其設定的屬性（年齡、職業、收入、人格特質等）做出擬真反應，讓您在安全的環境中練習各種銷售情境。</p><h2 id="進入練習" tabindex="-1">進入練習 <a class="header-anchor" href="#進入練習" aria-label="Permalink to &quot;進入練習&quot;">​</a></h2><p>從以下入口進入對話練習頁面：</p><ul><li>儀表板的 <strong>「開始對話」</strong> 按鈕</li><li>練習歷史的 <strong>「重新挑戰」</strong> 或 <strong>「繼續練習」</strong> 按鈕</li></ul><hr><h2 id="場景選擇" tabindex="-1">場景選擇 <a class="header-anchor" href="#場景選擇" aria-label="Permalink to &quot;場景選擇&quot;">​</a></h2><p>進入練習頁面後，首先選擇練習場景。系統提供以下選項：</p><h3 id="隨機角色" tabindex="-1">隨機角色 <a class="header-anchor" href="#隨機角色" aria-label="Permalink to &quot;隨機角色&quot;">​</a></h3><ul><li><strong>說明</strong>：系統將為您隨機選擇一個角色進行對話練習</li><li><strong>適用情境</strong>：想快速開始練習、不需特定客戶類型時</li><li><strong>行為</strong>：點擊後直接開始產生角色，無需額外設定</li></ul><h3 id="自訂角色" tabindex="-1">自訂角色 <a class="header-anchor" href="#自訂角色" aria-label="Permalink to &quot;自訂角色&quot;">​</a></h3><ul><li><strong>說明</strong>：您可以自行定義角色以進行對話練習</li><li><strong>適用情境</strong>：想針對特定客戶類型訓練（例如高收入已婚客戶）</li><li><strong>行為</strong>：點擊後開啟「客戶樣態設定」面板</li></ul><h3 id="重新對練-來自歷史紀錄" tabindex="-1">重新對練（來自歷史紀錄） <a class="header-anchor" href="#重新對練-來自歷史紀錄" aria-label="Permalink to &quot;重新對練（來自歷史紀錄）&quot;">​</a></h3><ul><li><strong>說明</strong>：使用與之前練習相同的客戶角色，開啟全新對話</li><li><strong>適用情境</strong>：想對同一位客戶嘗試不同策略</li><li><strong>入口</strong>：僅透過儀表板或練習歷史的「重新挑戰」按鈕觸發</li></ul><h3 id="繼續對練-來自歷史紀錄" tabindex="-1">繼續對練（來自歷史紀錄） <a class="header-anchor" href="#繼續對練-來自歷史紀錄" aria-label="Permalink to &quot;繼續對練（來自歷史紀錄）&quot;">​</a></h3><ul><li><strong>說明</strong>：接續之前未完成的對話</li><li><strong>適用情境</strong>：上次練習中途離開，想繼續完成</li><li><strong>入口</strong>：僅透過儀表板或練習歷史的「繼續練習」按鈕觸發</li><li><strong>特別說明</strong>：客戶對上次對話有模糊印象，您可以藉由上次對話的內容繼續互動</li></ul><hr><h2 id="客戶樣態設定" tabindex="-1">客戶樣態設定 <a class="header-anchor" href="#客戶樣態設定" aria-label="Permalink to &quot;客戶樣態設定&quot;">​</a></h2><p>選擇「自訂角色」後，會開啟客戶樣態設定面板。所有欄位皆為選填，未設定的項目會由 AI 自動補充。</p><h3 id="基本資料" tabindex="-1">基本資料 <a class="header-anchor" href="#基本資料" aria-label="Permalink to &quot;基本資料&quot;">​</a></h3><table tabindex="0"><thead><tr><th>欄位</th><th>類型</th><th>選項 / 範圍</th><th>說明</th></tr></thead><tbody><tr><td>年齡</td><td>下拉選單</td><td>18 ~ 65 歲</td><td>客戶年齡</td></tr><tr><td>性別</td><td>下拉選單</td><td>男 / 女</td><td>客戶性別</td></tr><tr><td>個性 (MBTI)</td><td>下拉選單</td><td>16 種 MBTI 類型</td><td>影響客戶的溝通風格與反應模式</td></tr><tr><td>教育程度</td><td>下拉選單</td><td>小學 / 國中 / 高中 / 大學 / 碩士 / 博士</td><td>客戶教育背景</td></tr><tr><td>收入</td><td>下拉選單</td><td>5M~10M / 10M~15M / 15M~20M / 大於 20M</td><td>客戶年收入等級</td></tr><tr><td>職業</td><td>搜尋選單</td><td>100+ 種職業選項</td><td>支援關鍵字搜尋，輸入後即時過濾</td></tr></tbody></table><h3 id="mbti-人格類型" tabindex="-1">MBTI 人格類型 <a class="header-anchor" href="#mbti-人格類型" aria-label="Permalink to &quot;MBTI 人格類型&quot;">​</a></h3><p>點擊「個性」欄位旁的提示圖示，可開啟 MBTI 說明視窗，查看各類型的詳細描述：</p><table tabindex="0"><thead><tr><th>類型</th><th>名稱</th><th>特點概述</th></tr></thead><tbody><tr><td>ISTJ</td><td>物流師 (Logistician)</td><td>嚴謹務實、重視規則</td></tr><tr><td>ISFJ</td><td>守衛者 (Defender)</td><td>溫暖可靠、樂於助人</td></tr><tr><td>INFJ</td><td>提倡者 (Advocate)</td><td>深思熟慮、富有同理心</td></tr><tr><td>INTJ</td><td>建築師 (Architect)</td><td>獨立自主、追求效率</td></tr><tr><td>ISTP</td><td>鑑賞家 (Virtuoso)</td><td>冷靜分析、動手能力強</td></tr><tr><td>ISFP</td><td>探隊家 (Adventurer)</td><td>溫和敏感、重視和諧</td></tr><tr><td>INFP</td><td>調停者 (Mediator)</td><td>富創造力、價值觀驅動</td></tr><tr><td>INTP</td><td>邏輯學家 (Logician)</td><td>邏輯思維、好奇心強</td></tr><tr><td>ESTP</td><td>企業家 (Entrepreneur)</td><td>行動派、喜歡冒險</td></tr><tr><td>ESFP</td><td>表演者 (Entertainer)</td><td>外向熱情、享受當下</td></tr><tr><td>ENFP</td><td>競選者 (Campaigner)</td><td>充滿活力、善於溝通</td></tr><tr><td>ENTP</td><td>辯論家 (Debater)</td><td>機智敏銳、喜歡挑戰</td></tr><tr><td>ESTJ</td><td>總經理 (Executive)</td><td>組織能力強、講求效率</td></tr><tr><td>ESFJ</td><td>執政官 (Consul)</td><td>重視團體、關心他人</td></tr><tr><td>ENFJ</td><td>主人公 (Protagonist)</td><td>領導力強、鼓舞人心</td></tr><tr><td>ENTJ</td><td>指揚官 (Commander)</td><td>果斷有魄力、目標導向</td></tr></tbody></table><h3 id="家庭狀況" tabindex="-1">家庭狀況 <a class="header-anchor" href="#家庭狀況" aria-label="Permalink to &quot;家庭狀況&quot;">​</a></h3><table tabindex="0"><thead><tr><th>欄位</th><th>類型</th><th>選項 / 範圍</th><th>說明</th></tr></thead><tbody><tr><td>婚姻狀況</td><td>下拉選單</td><td>單身 / 已婚</td><td>影響客戶的保險需求面向</td></tr><tr><td>配偶年齡</td><td>下拉選單</td><td>18 ~ 65 歲</td><td>僅在「已婚」時可選擇</td></tr><tr><td>子女數量</td><td>下拉選單</td><td>0 ~ 10 人</td><td>設定後可進一步設定每位子女的性別與年齡</td></tr></tbody></table><p>當子女數量 &gt; 0 時，會動態展開每位子女的設定欄位：</p><table tabindex="0"><thead><tr><th>欄位</th><th>類型</th><th>說明</th></tr></thead><tbody><tr><td>子女 N 性別</td><td>下拉選單</td><td>男 / 女</td></tr><tr><td>子女 N 年齡</td><td>下拉選單</td><td>最大年齡 = 客戶年齡 - 18</td></tr></tbody></table><h3 id="與業務員關係" tabindex="-1">與業務員關係 <a class="header-anchor" href="#與業務員關係" aria-label="Permalink to &quot;與業務員關係&quot;">​</a></h3><table tabindex="0"><thead><tr><th>欄位</th><th>類型</th><th>說明</th></tr></thead><tbody><tr><td>是否為陌生客戶？</td><td>開關切換</td><td>預設為「是」（陌生客）。關閉後切換為「親友」模式</td></tr></tbody></table><p>當設定為 <strong>親友</strong> 時，會展開以下額外欄位：</p><table tabindex="0"><thead><tr><th>欄位</th><th>類型</th><th>說明</th></tr></thead><tbody><tr><td>我對客戶稱謂</td><td>文字輸入</td><td>您如何稱呼客戶？例如：小王、王大哥</td></tr><tr><td>認識時間</td><td>文字輸入</td><td>從小到大、3年、5年、10年...</td></tr><tr><td>與業務員關係描述</td><td>文字區域（必填）</td><td>描述您與客戶的關係背景</td></tr></tbody></table><h4 id="關係描述範本" tabindex="-1">關係描述範本 <a class="header-anchor" href="#關係描述範本" aria-label="Permalink to &quot;關係描述範本&quot;">​</a></h4><p>系統提供 5 個預設範本供快速套用：</p><ol><li><strong>舊客戶</strong> — 長期保險客戶的關係描述</li><li><strong>親戚</strong> — 家族親戚關係的描述</li><li><strong>前同事</strong> — 前公司同事的關係描述</li><li><strong>同學</strong> — 學校同學的關係描述</li><li><strong>陌生訪談</strong> — 街頭訪問式的關係描述</li></ol><h3 id="操作按鈕" tabindex="-1">操作按鈕 <a class="header-anchor" href="#操作按鈕" aria-label="Permalink to &quot;操作按鈕&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按鈕</th><th>說明</th></tr></thead><tbody><tr><td>清除所有</td><td>重設所有欄位為初始值</td></tr><tr><td>記錄</td><td>開啟歷史設定紀錄列表，可載入之前使用過的角色設定。最多可儲存一定筆數的紀錄</td></tr><tr><td>取消</td><td>關閉設定面板，不進行任何操作</td></tr><tr><td>確認</td><td>使用目前設定開始練習</td></tr></tbody></table><h3 id="輸入驗證" tabindex="-1">輸入驗證 <a class="header-anchor" href="#輸入驗證" aria-label="Permalink to &quot;輸入驗證&quot;">​</a></h3><ul><li>所有文字輸入欄位會進行安全性檢查（防止 XSS / SQL 注入）</li><li>親友模式下「關係描述」為必填欄位</li><li>不安全字元會顯示警告：「請勿輸入特殊字元」</li></ul><hr><h2 id="角色生成" tabindex="-1">角色生成 <a class="header-anchor" href="#角色生成" aria-label="Permalink to &quot;角色生成&quot;">​</a></h2><p>確認設定後（或選擇隨機角色後），系統會進入角色生成階段：</p><ul><li>畫面顯示載入動畫與場景資訊</li><li>提示訊息：「提示：生成需要一些時間，請耐心等候。」</li><li>生成完成後自動進入對話介面</li></ul><p>生成的客戶角色包含完整的個人資料，即使您只設定了部分屬性，AI 也會自動補齊其餘欄位。</p><hr><h2 id="對話介面" tabindex="-1">對話介面 <a class="header-anchor" href="#對話介面" aria-label="Permalink to &quot;對話介面&quot;">​</a></h2><h3 id="版面配置" tabindex="-1">版面配置 <a class="header-anchor" href="#版面配置" aria-label="Permalink to &quot;版面配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>區域</th><th>位置</th><th>說明</th></tr></thead><tbody><tr><td>客戶資訊側邊欄</td><td>左側</td><td>顯示客戶的完整角色設定資料，可收合</td></tr><tr><td>場景說明</td><td>對話區上方</td><td>說明本次對話的情境背景</td></tr><tr><td>對話訊息列表</td><td>中央</td><td>您與 AI 客戶的對話紀錄，自動捲動至最新訊息</td></tr><tr><td>訊息輸入區</td><td>下方</td><td>文字輸入框與傳送按鈕</td></tr><tr><td>計時器</td><td>右上方</td><td>顯示目前練習時長（MM:SS 格式）</td></tr><tr><td>結束對話按鈕</td><td>計時器旁</td><td>點擊可結束本次練習</td></tr></tbody></table><h3 id="場景說明" tabindex="-1">場景說明 <a class="header-anchor" href="#場景說明" aria-label="Permalink to &quot;場景說明&quot;">​</a></h3><p>根據不同的練習模式，場景說明會有所不同：</p><table tabindex="0"><thead><tr><th>模式</th><th>場景說明</th></tr></thead><tbody><tr><td>新對話（陌生客）</td><td>「您是第一次與 {客戶名} 對話」</td></tr><tr><td>新對話（親友）</td><td>「您與 {客戶名} 互相認識，但電話並沒有顯示您的個人資訊」</td></tr><tr><td>繼續對練</td><td>「您與 {客戶名} 不久前通過電話。他對上次對話有些模糊的印象，您可以藉由上次對話的內容，繼續與他對話。」</td></tr></tbody></table><p>所有模式都會提醒：「請先查閱左方的客戶資料，了解客戶的保險需求，再進行聊天。」</p><h3 id="發送訊息" tabindex="-1">發送訊息 <a class="header-anchor" href="#發送訊息" aria-label="Permalink to &quot;發送訊息&quot;">​</a></h3><ol><li>在輸入框中輸入文字（預設提示文字：「傳送訊息至 PASSION Agent...」）</li><li>按 <strong>Enter</strong> 或點擊 <strong>傳送按鈕</strong> 發送</li><li>等待 AI 客戶回應（回應過程中輸入框暫時停用）</li><li>AI 回應完成後即可繼續對話</li></ol><blockquote><p>輸入區下方提示：「PASSION Agent 可能會產生不準確的訊息。請驗證重要數據並遵循適用的法規和政策。」</p></blockquote><h3 id="內容安全檢測" tabindex="-1">內容安全檢測 <a class="header-anchor" href="#內容安全檢測" aria-label="Permalink to &quot;內容安全檢測&quot;">​</a></h3><p>系統內建內容安全機制。當您的訊息觸發安全檢測時，訊息不會被送出，並顯示對應的提示訊息：</p><table tabindex="0"><thead><tr><th>檢測類型</th><th>提示訊息</th></tr></thead><tbody><tr><td>越權操作/繞過安全</td><td>系統偵測到疑似越權操作或嘗試繞過安全限制，請避免輸入可疑內容</td></tr><tr><td>不當或高風險內容</td><td>系統偵測到疑似不當或高風險內容，請避免輸入具爭議、危險或不適當的訊息</td></tr><tr><td>非法或高敏感內容</td><td>系統偵測到疑似非法或高敏感內容，請勿輸入違法資訊</td></tr><tr><td>個資或敏感資料</td><td>系統偵測到疑似個資或敏感資料（如電話、地址、身分證號等），請避免輸入個人資訊</td></tr><tr><td>惡意連結</td><td>系統偵測到疑似危險或惡意連結，請避免輸入不安全的網址</td></tr></tbody></table><hr><h2 id="銷售階段" tabindex="-1">銷售階段 <a class="header-anchor" href="#銷售階段" aria-label="Permalink to &quot;銷售階段&quot;">​</a></h2><p>AI Coach 的練習圍繞多個銷售階段進行。各階段的定義與數量由管理員設定，常見的階段例如：</p><table tabindex="0"><thead><tr><th>階段</th><th>目標</th><th>說明</th></tr></thead><tbody><tr><td>第 1 階段</td><td>破冰/建立信任</td><td>與客戶建立初步信任關係，了解基本狀況</td></tr><tr><td>第 2 階段</td><td>需求探索</td><td>深入了解客戶的保險需求與擔憂</td></tr><tr><td>第 3 階段</td><td>方案說明</td><td>針對客戶需求提供合適的保險方案</td></tr><tr><td>第 4 階段</td><td>異議處理</td><td>回應客戶的疑慮與反對意見</td></tr><tr><td>第 5 階段</td><td>促成</td><td>引導客戶做出購買決定</td></tr></tbody></table><blockquote><p>實際階段名稱與數量依公司管理員設定為準。</p></blockquote><h3 id="階段判定方式" tabindex="-1">階段判定方式 <a class="header-anchor" href="#階段判定方式" aria-label="Permalink to &quot;階段判定方式&quot;">​</a></h3><p>階段<strong>不會在對話過程中即時顯示</strong>。對話結束後，AI 會回顧完整對話內容，分析您在每個階段的表現，判定您最終達成了哪個階段。結果會呈現在評量報告的「階段評量」區塊中。</p><p>換句話說，對話過程中請專注於與客戶的互動，不需擔心「目前在第幾階段」。階段評量是事後回顧式的分析，不影響對話進行。</p><hr><h2 id="結束對話" tabindex="-1">結束對話 <a class="header-anchor" href="#結束對話" aria-label="Permalink to &quot;結束對話&quot;">​</a></h2><h3 id="主動結束" tabindex="-1">主動結束 <a class="header-anchor" href="#主動結束" aria-label="Permalink to &quot;主動結束&quot;">​</a></h3><ol><li>點擊右上方的 <strong>「結束對話」</strong> 按鈕</li><li>系統彈出確認對話框</li><li>確認後，系統會自動結束對話並開始產生評量報告</li><li>頁面跳轉至評量報告頁面</li></ol><blockquote><p>注意：AI 回應進行中時，「結束對話」按鈕暫時停用。</p></blockquote><h3 id="客戶發起結束" tabindex="-1">客戶發起結束 <a class="header-anchor" href="#客戶發起結束" aria-label="Permalink to &quot;客戶發起結束&quot;">​</a></h3><p>當 AI 客戶在對話中表達想要結束時，頁面頂部會出現通知列：</p><ul><li>標題：「客戶想結束對話」</li><li>描述：「您要繼續對話還是結束本次對話？」</li><li>兩個選項： <ul><li><strong>繼續對話</strong> — 忽略客戶的結束意圖，嘗試繼續溝通</li><li><strong>結束對話</strong> — 同意結束，進入評量產生流程</li></ul></li></ul><h3 id="結束後的處理" tabindex="-1">結束後的處理 <a class="header-anchor" href="#結束後的處理" aria-label="Permalink to &quot;結束後的處理&quot;">​</a></h3><p>對話結束後，系統會在背景自動進行以下處理：</p><ol><li><strong>儲存對話紀錄</strong> — 記錄練習時長與所有對話內容</li><li><strong>產生階段評量</strong> — AI 分析您在各銷售階段的表現</li><li><strong>產生綜合評核</strong> — AI 撰寫完整的表現評估報告</li><li><strong>初始化回饋評分</strong> — 建立每則訊息的評分記錄（預設中立）</li></ol><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>了解 <a href="./evaluation.html">評量報告</a> 的詳細內容</li><li>查看 <a href="./history.html">練習歷史</a> 回顧過去的練習</li><li>使用 <a href="./knowledge-assistant.html">知識助手</a> 查詢銷售知識</li></ul>',82)])])}const g=d(l,[["render",o]]);export{c as __pageData,g as default};
